class Solution {
    public boolean isPossible(int[] nums) {
        Map<Integer, Integer> map = new HashMap<>();
        for (int num : nums) {
            map.put(num, map.getOrDefault(num, 0) + 1);
        }
        for (int num : nums) {
            if (map.get(num) > 0) {
                int count = map.get(num);
                int next = num + 1;
                int nextNext = num + 2;
                if (map.containsKey(next) && map.containsKey(nextNext)) {
                    int nextCount = map.get(next);
                    int nextNextCount = map.get(nextNext);
                    if (nextCount >= count && nextNextCount >= count) {
                        map.put(num, count - 1);
                        map.put(next, nextCount - count);
                        map.put(nextNext, nextNextCount - count);
                    } else {
                        return false;
                    }
                } else {
                    return false;
                }
            }
        }
        return true;
    }
}
